      "konten": "package main

import (
	"fmt"
	"go-interface-example/shapes"
)

// printArea menerima sebuah Shape dan mencetak luasnya.
// Fungsi ini tidak peduli apa tipe konkret dari shape tersebut,
// selama tipe tersebut memenuhi kontrak dari interface Shape.
func printArea(s shapes.Shape) {
	fmt.Printf("Luas dari bentuk ini adalah %0.2f\n", s.Area())
}

func main() {
	// Membuat instance dari tipe konkret
	rect := shapes.Rectangle{Width: 10, Height: 5}
	circ := shapes.Circle{Radius: 7}

	// Memanggil fungsi printArea dengan tipe yang berbeda.
	// Keduanya valid karena mengimplementasikan interface Shape.
	fmt.Println("Menghitung luas persegi panjang:")
	printArea(rect)

	fmt.Println("\nMenghitung luas lingkaran:")
	printArea(circ)

	// Kita juga bisa membuat sebuah slice dari interface Shape
	// untuk menampung berbagai macam bentuk.
	shapeCollection := []shapes.Shape{
		shapes.Rectangle{Width: 4, Height: 8},
		shapes.Circle{Radius: 3},
		shapes.Rectangle{Width: 2.5, Height: 10},
	}

	fmt.Println("\nMenghitung luas dari koleksi bentuk:")
	for _, s := range shapeCollection {
		printArea(s)
	}
}
