      "konten": "package shapes

import "math"

// Shape adalah interface yang mendefinisikan kontrak untuk bentuk geometris.
// Setiap bentuk yang mengimplementasikan interface ini harus memiliki metode Area().
type Shape interface {
	Area() float64
}

// Rectangle adalah struct yang merepresentasikan persegi panjang.
type Rectangle struct {
	Width  float64
	Height float64
}

// Area mengimplementasikan metode dari interface Shape untuk Rectangle.
// Ini menghitung luas persegi panjang.
func (r Rectangle) Area() float64 {
	return r.Width * r.Height
}

// Circle adalah struct yang merepresentasikan lingkaran.
type Circle struct {
	Radius float64
}

// Area mengimplementasikan metode dari interface Shape untuk Circle.
// Ini menghitung luas lingkaran.
func (c Circle) Area() float64 {
	return math.Pi * c.Radius * c.Radius
}
